#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long modPow(long long a, long long e) {
    long long r = 1;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int C[205];
        int total = 0;
        for (int i = 0; i < N; ++i) { scanf("%d", &C[i]); total += C[i]; }
        // factorials
        long long fact[205], invFact[205];
        fact[0] = 1;
        for (int i = 1; i <= total; ++i) fact[i] = fact[i-1] * i % MOD;
        invFact[total] = modPow(fact[total], MOD-2);
        for (int i = total; i > 0; --i) invFact[i-1] = invFact[i] * i % MOD;
        // DP
        long long *dp = (long long*)calloc(total+1, sizeof(long long));
        long long *ndp = (long long*)calloc(total+1, sizeof(long long));
        dp[0] = 1;
        int curMax = 0;
        for (int idx = 0; idx < N; ++idx) {
            int c = C[idx];
            for (int i = 0; i <= total; ++i) ndp[i] = 0;
            for (int len = 0; len <= curMax; ++len) if (dp[len]) {
                for (int k = 0; k <= c-1; ++k) {
                    int blocks = c - k;
                    int nlen = len + blocks;
                    long long ways = dp[len];
                    // C(c-1, k)
                    long long comb = fact[c-1] * invFact[k] % MOD * invFact[c-1-k] % MOD;
                    ways = ways * comb % MOD;
                    ways = ways * invFact[blocks] % MOD; // divide by (c-k)!
                    if (k & 1) ways = (MOD - ways) % MOD; // sign
                    ndp[nlen] = (ndp[nlen] + ways) % MOD;
                }
            }
            curMax += c; // after processing this colour maximum possible length
            long long *tmp = dp; dp = ndp; ndp = tmp;
        }
        long long ans = 0;
        for (int len = 0; len <= total; ++len) {
            ans = (ans + dp[len] * fact[len]) % MOD;
        }
        printf("%lld\n", ans);
        free(dp); free(ndp);
    }
    return 0;
}

